sql:
SELECT plan_name, AVG(monthly_charge) AS average_monthly_charge
FROM billing_plans
WHERE billing_plan_status = 'active';

SELECT city, population
FROM population
ORDER BY population DESC;

SELECT COUNT(customer_id) AS churned_customers
FROM churn_status
WHERE churn_category = 'Churned';

SELECT SUM(population) AS total_population
FROM population
WHERE city = '1';

SELECT churn_category, COUNT(*) AS customer_count
FROM churn_status
GROUP BY churn_category;

SELECT AVG(monthly_charge) AS average_monthly_charge
FROM billing_plans
WHERE billing_plan_status = 'active';

external_knowledge:
- Customer churn refers to the loss of customers to a competitor or the voluntary termination of a service; 
- Average tenure is the mean duration a customer has been subscribed to a service; 
- Average monthly charge is the mean amount a customer pays each month.

sql:
SELECT DISTINCT churn_category
FROM churn_status
WHERE churn_category = 'Churned';

SELECT billing_cycle_type, AVG(monthly_charge) AS average_monthly_charge
FROM billing_plans
GROUP BY billing_cycle_type;

SELECT churn_category, churn_reason
FROM churn_status
WHERE churn_category = 'Churned';

SELECT customer_id, age, number_of_dependents
FROM customers
ORDER BY age DESC;

SELECT customer_id
FROM churn_status
WHERE churn_category = 'Churned' AND churn_reason_category = 'Service Issues';

SELECT COUNT(customer_id) AS total_churned_customers
FROM churn_status
WHERE churn_category = 'Churned';
